68	         retVar(i) := foo(i);
69	      end loop;
70	      retVar(PROTOCOL_SIZE_G) := ICMP_C;
71	      if IGMP_G then
72	         retVar(PROTOCOL_SIZE_G+1) := IGMP_C;
73	      end if;
74	      return retVar;
75	   end function;
